export const meta = {
  name: 'understand-opencore-complete',
  description: 'Complete knowledge graph analysis of OpenCoreAnalysisKit',
  phases: [
    { title: 'Prepare', detail: 'Read scan results and prepare batches' },
    { title: 'Analyze Files', detail: 'Extract knowledge graph from source files' },
    { title: 'Analyze Domain', detail: 'Extract business domain knowledge' },
    { title: 'Review Graph', detail: 'Validate knowledge graph quality' },
    { title: 'Build Tour', detail: 'Create learning tour through codebase' },
  ],
}

const PROJECT_ROOT = '/home/cwtrocks/OpenCoreAnalysisKit'
const UA_DIR = `${PROJECT_ROOT}/.understand-anything`
const INTERMEDIATE_DIR = `${UA_DIR}/intermediate`

phase('Prepare')
log('Reading scan results and layers...')

// Read the scan and layer results
const scanResult = await agent('Read and parse the scan-result.json file', {
  phase: 'Prepare',
  schema: {
    type: 'object',
    properties: {
      files: { type: 'array' },
      totalFiles: { type: 'number' }
    }
  }
})

const layers = await agent('Read and parse the layers.json file', {
  phase: 'Prepare',
  schema: {
    type: 'object',
    properties: {
      layers: { type: 'array' }
    }
  }
})

log(`Scanned ${scanResult?.totalFiles || 559} files across ${layers?.layers?.length || 11} architectural layers`)

phase('Analyze Files')
log('Starting batch file analysis to extract knowledge graph nodes and edges...')

// For a 559-file project, we'll process in multiple batches
// Let's do 10 parallel batches to keep it manageable
const BATCH_SIZE = 60
const NUM_BATCHES = 10

log(`Processing files in ${NUM_BATCHES} parallel batches (${BATCH_SIZE} files each)`)

const fileAnalysisResults = await parallel(
  Array.from({ length: NUM_BATCHES }, (_, i) => async () => {
    const batchNum = i + 1
    return await agent(
      `Analyze batch ${batchNum}/${NUM_BATCHES} of OpenCoreAnalysisKit source files. Extract knowledge graph nodes (files, functions, classes, data structures) and edges (calls, includes, extends) for files in this batch. Use the scan-result.json and layers.json for context.`,
      {
        label: `File batch ${batchNum}`,
        phase: 'Analyze Files',
      }
    )
  })
)

log(`Completed file analysis: ${fileAnalysisResults.filter(Boolean).length}/${NUM_BATCHES} batches succeeded`)

phase('Analyze Domain')
log('Extracting business domain knowledge and flows...')

const domainAnalysis = await agent(
  `Analyze the OpenCoreAnalysisKit codebase at ${PROJECT_ROOT} to extract business domain knowledge. Identify domains (e.g., "ELF Parsing", "ART Runtime Mirroring", "Stack Unwinding"), business flows (e.g., "Load Coredump → Parse ELF → Extract Threads → Build Stacktraces"), and process steps. This is a C++ tool for Android coredump analysis.`,
  {
    phase: 'Analyze Domain',
    agentType: 'understand-anything:domain-analyzer'
  }
)

phase('Review Graph')
log('Validating knowledge graph for correctness and completeness...')

const graphReview = await agent(
  `Review the generated knowledge graph in ${UA_DIR} for OpenCoreAnalysisKit. Check for correctness (accurate node types, valid edge relationships), completeness (all major components covered), and quality (meaningful summaries, appropriate complexity ratings). Render approval or rejection with specific feedback.`,
  {
    phase: 'Review Graph',
    agentType: 'understand-anything:graph-reviewer'
  }
)

phase('Build Tour')
log('Creating guided learning tour through the codebase...')

const tour = await agent(
  `Design a guided learning tour (5-15 pedagogical steps) through the OpenCoreAnalysisKit codebase at ${PROJECT_ROOT}. The tour should teach newcomers about the project architecture and key concepts in logical order. Focus on: 1) Entry point and command system, 2) ELF core file parsing, 3) ART runtime object model mirroring, 4) Heap walking and object inspection, 5) Stack unwinding across architectures.`,
  {
    phase: 'Build Tour',
    agentType: 'understand-anything:tour-builder'
  }
)

log('Knowledge graph analysis complete!')

return {
  scanResult,
  layers,
  fileAnalysisBatches: fileAnalysisResults.filter(Boolean).length,
  domainAnalysis,
  graphReview,
  tour,
  outputDir: UA_DIR
}
